// ============================================================
// Authorization Middleware (role-based & permission-based)
// ============================================================

function authorize(...requiredRoles) {
  return function authorizeMiddleware(req, res, next) {
    if (!req.user) {
      return res.status(401).json({
        error: 'AUTHENTICATION_REQUIRED',
        message: 'Authentication is required',
      });
    }

    const hasRole = requiredRoles.some(role => req.user.roles.includes(role));
    if (!hasRole) {
      return res.status(403).json({
        error: 'INSUFFICIENT_ROLE',
        message: `Required roles: ${requiredRoles.join(', ')}`,
      });
    }

    next();
  };
}

function requirePermissions(...requiredPermissions) {
  return function permissionMiddleware(req, res, next) {
    if (!req.user) {
      return res.status(401).json({
        error: 'AUTHENTICATION_REQUIRED',
        message: 'Authentication is required',
      });
    }

    const hasAll = requiredPermissions.every(perm => req.user.permissions.includes(perm));
    if (!hasAll) {
      return res.status(403).json({
        error: 'INSUFFICIENT_PERMISSIONS',
        message: `Required permissions: ${requiredPermissions.join(', ')}`,
      });
    }

    next();
  };
}

// ============================================================
// Rate limiting per-user (simple in-memory sliding window)
// ============================================================

class SlidingWindowRateLimiter {
  constructor(windowMs = 60000, maxRequests = 100) {
    this.windowMs = windowMs;
    this.maxRequests = maxRequests;
    this.windows = new Map();

    // Periodic cleanup every 5 minutes
    setInterval(() => this._cleanup(), 5 * 60 * 1000).unref();
  }

  isAllowed(key) {
    const now = Date.now();
    const windowStart = now - this.windowMs;

    let timestamps = this.windows.get(key);
    if (!timestamps) {
      timestamps = [];
      this.windows.set(key, timestamps);
    }

    // Remove expired entries
    while (timestamps.length > 0 && timestamps[0] < windowStart) {
      timestamps.shift();
    }

    if (timestamps.length >= this.maxRequests) {
      return {
        allowed: false,
        remaining: 0,
        resetAt: timestamps[0] + this.windowMs,
      };
    }

    timestamps.push(now);
    return {
      allowed: true,
      remaining: this.maxRequests - timestamps.length,
      resetAt: now + this.windowMs,
    };
  }

  _cleanup() {
    const now = Date.now();
    for (const [key, timestamps] of this.windows) {
      while (timestamps.length > 0 && timestamps[0] < now - this.windowMs) {
        timestamps.shift();
      }
      if (timestamps.length === 0) {
        this.windows.delete(key);
      }
    }
  }
}

function rateLimit(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    keyExtractor = (req) => req.user ? req.user.id : req.ip,
  } = options;

  const limiter = new SlidingWindowRateLimiter(windowMs, maxRequests);

  return function rateLimitMiddleware(req, res, next) {
    const key = keyExtractor(req);
    const result = limiter.isAllowed(key);

    res.set('X-RateLimit-Limit', String(maxRequests));
    res.set('X-RateLimit-Remaining', String(result.remaining));
    res.set('X-RateLimit-Reset', String(Math.ceil(result.resetAt / 1000)));

    if (!result.allowed) {
      return res.status(429).json({
        error: 'RATE_LIMIT_EXCEEDED',
        message: 'Too many requests',
        retryAfter: Math.ceil((result.resetAt - Date.now()) / 1000),
      });
    }

    next();
  };
}

